/**
 * Custom hook for handling image uploads with immediate preview
 * Author: generated by Amazon Q
 * Created: 2024-12-20
 */

import { useState, useCallback } from 'react';

interface UseImageUploadOptions {
  type: 'logo' | 'logo-light' | 'logo-dark' | 'favicon' | 'media';
  onSuccess?: (url: string) => void;
  onError?: (error: string) => void;
}

interface UseImageUploadReturn {
  preview: string;
  isUploading: boolean;
  uploadImage: (file: File) => Promise<void>;
  setPreview: (url: string) => void;
  clearPreview: () => void;
}

export function useImageUpload({ 
  type, 
  onSuccess, 
  onError 
}: UseImageUploadOptions): UseImageUploadReturn {
  const [preview, setPreview] = useState<string>('');
  const [isUploading, setIsUploading] = useState(false);

  const uploadImage = useCallback(async (file: File) => {
    if (!file) return;

    setIsUploading(true);

    // Create immediate preview
    const previewUrl = URL.createObjectURL(file);
    setPreview(previewUrl);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('type', type);

    try {
      const response = await fetch('/api/admin/upload', {
        method: 'POST',
        body: formData
      });

      const data = await response.json();
      
      if (response.ok && data.success) {
        // Keep the blob URL for a moment to ensure smooth transition
        setTimeout(() => {
          URL.revokeObjectURL(previewUrl);
        }, 1000);
        
        // Set server URL with cache busting
        const serverUrl = `${data.url}?t=${Date.now()}`;
        setPreview(serverUrl);
        
        // Call success with the clean server URL (without cache busting for storage)
        onSuccess?.(data.url);
      } else {
        // Revert preview on error
        URL.revokeObjectURL(previewUrl);
        setPreview('');
        onError?.(data.error || 'Upload failed');
      }
    } catch (error) {
      // Revert preview on error
      URL.revokeObjectURL(previewUrl);
      setPreview('');
      onError?.(error instanceof Error ? error.message : 'Upload failed');
    } finally {
      setIsUploading(false);
    }
  }, [type, onSuccess, onError]);

  const clearPreview = useCallback(() => {
    if (preview.startsWith('blob:')) {
      URL.revokeObjectURL(preview);
    }
    setPreview('');
  }, [preview]);

  return {
    preview,
    isUploading,
    uploadImage,
    setPreview,
    clearPreview
  };
}